## 9. State Management Integration

```typescript
// In App.tsx or parent component
function useProgressCardData(projectPath: string) {
  const { state, actions } = appMachine.useMachine('features');
  const [session, setSession] = useState<SessionInfo | null>(null);
  const [lastCommit, setLastCommit] = useState<CommitInfo | null>(null);

  // Load features
  useEffect(() => {
    actions.load(projectPath);
  }, [projectPath]);

  // Load session from progress.txt via RPC
  useEffect(() => {
    invoke('harness:read_progress', { path: projectPath })
      .then(parseProgressFile)
      .then(setSession);
  }, [projectPath]);

  // Get last commit via RPC
  useEffect(() => {
    invoke('git:last_commit', { path: projectPath })
      .then(setLastCommit);
  }, [projectPath]);

  // Calculate stats
  const stats = selectors.featureStats(state);
  const activeFeature = state.items?.find(f => !f.passes);

  return { stats, session, lastCommit, activeFeature, isLoading: state.loading };
}
```

